#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38F
#endif

__kernel void find_nearest_points_kernel(
    const float *features,
    const float *clusters,
    int *membership,
    int npoints,
    int nfeatures,
    int nclusters,
    int *partial_counts,
    float *partial_sums,
    float *delta_contrib)
{
    int i = get_global_id(0);
    if (i >= npoints) return;

    int best_index = 0;
    float min_dist = FLT_MAX;

    const float *pt = features + (i * nfeatures);

    for (int c = 0; c < nclusters; c++) {
        const float *center = clusters + (c * nfeatures);
        float dist = 0.0f;
        for (int d = 0; d < nfeatures; d++) {
            float diff = pt[d] - center[d];
            dist += diff * diff;
        }

        if (dist < min_dist) {
            min_dist = dist;
            best_index = c;
        }
    }

    int old_membership = membership[i];
    if (old_membership != best_index) {
        delta_contrib[0] += 1.0f;
    }
    membership[i] = best_index;

    partial_counts[best_index]++;
    for (int d = 0; d < nfeatures; d++) {
        partial_sums[best_index * nfeatures + d] += pt[d];
    }
}

__kernel void reset_partial_arrays_kernel(
    int *partial_counts,
    float *partial_sums,
    int nclusters,
    int nfeatures)
{
    int idx = get_global_id(0);
    int total_size = nclusters * nfeatures;

    if (idx < nclusters) {
        partial_counts[idx] = 0;
    }
    if (idx < total_size) {
        partial_sums[idx] = 0.0f;
    }
}

__kernel void update_centers_kernel(
    float *clusters,
    const int *counts,
    const float *sums,
    int nclusters,
    int nfeatures)
{
    int c = get_global_id(0);
    if (c >= nclusters) return;

    int count = counts[c];
    if (count > 0) {
        for (int d = 0; d < nfeatures; d++) {
            clusters[c * nfeatures + d] = sums[c * nfeatures + d] / count;
        }
    }
}
